import React from "react";

const SEO = ({ title, description, path, lang, article }) => {
  const siteUrl = "https://solo.engineer";
  const ogImage = `${siteUrl}/og-image.png`;

  // Determine language-aware path
  const langPrefix = lang || "vi";
  const canonicalPath = path === "/" ? `/${langPrefix}/` : `/${langPrefix}${path}`;
  const fullUrl = `${siteUrl}${canonicalPath}`;

  // Alternate language URLs
  const altLang = langPrefix === "vi" ? "en" : "vi";
  const altPath = path === "/" ? `/${altLang}/` : `/${altLang}${path}`;
  const altUrl = `${siteUrl}${altPath}`;

  // Locale mapping
  const locales = { vi: "vi_VN", en: "en_US" };
  const locale = locales[langPrefix] || "vi_VN";

  const jsonLd = article
    ? {
        "@context": "https://schema.org",
        "@type": "Article",
        headline: title,
        description,
        url: fullUrl,
        image: ogImage,
        datePublished: article.publishedTime,
        dateModified: article.publishedTime,
        inLanguage: langPrefix === "vi" ? "vi" : "en",
        author: {
          "@type": "Organization",
          name: article.author || "Bobbie Intelligence",
          url: siteUrl,
        },
        publisher: {
          "@type": "Organization",
          name: "Bobbie Intelligence",
          logo: { "@type": "ImageObject", url: `${siteUrl}/logo.svg` },
        },
      }
    : {
        "@context": "https://schema.org",
        "@type": "WebSite",
        name: "Bobbie Intelligence",
        description,
        url: siteUrl,
        inLanguage: ["vi", "en"],
        potentialAction: {
          "@type": "SearchAction",
          target: `${siteUrl}/${langPrefix}/reports/?q={search_term_string}`,
          "query-input": "required name=search_term_string",
        },
      };

  const breadcrumbLd = {
    "@context": "https://schema.org",
    "@type": "BreadcrumbList",
    itemListElement: [
      { "@type": "ListItem", position: 1, name: "Home", item: `${siteUrl}/${langPrefix}/` },
      ...(path !== "/"
        ? [{ "@type": "ListItem", position: 2, name: title.replace(" — Bobbie Intelligence", "").replace(" — ", " "), item: fullUrl }]
        : []),
    ],
  };

  return (
    <>
      <html lang={langPrefix} />
      <title>{title}</title>
      <meta name="description" content={description} />
      <meta name="keywords" content="AI intelligence, crypto analysis, trend scouting, solo developer, market signals, opportunity radar, autonomous agents, Bobbie Intelligence" />
      <meta name="author" content="Bobbie Intelligence" />
      <meta name="robots" content="index, follow" />
      <meta name="theme-color" content="#FF7300" />
      <link rel="canonical" href={fullUrl} />
      <link rel="alternate" hrefLang="vi" href={path === "/" ? `${siteUrl}/vi/` : `${siteUrl}/vi${path}`} />
      <link rel="alternate" hrefLang="en" href={path === "/" ? `${siteUrl}/en/` : `${siteUrl}/en${path}`} />
      <link rel="alternate" hrefLang="x-default" href={`${siteUrl}/vi${path === "/" ? "/" : path}`} />

      {/* Favicon */}
      <link rel="icon" type="image/svg+xml" href="/favicon.svg" />
      <link rel="icon" type="image/png" sizes="32x32" href="/favicon-32x32.png" />
      <link rel="icon" type="image/png" sizes="16x16" href="/favicon-16x16.png" />
      <link rel="manifest" href="/site.webmanifest" />

      {/* iOS PWA */}
      <meta name="apple-mobile-web-app-capable" content="yes" />
      <meta name="apple-mobile-web-app-status-bar-style" content="black-translucent" />
      <meta name="apple-mobile-web-app-title" content="Bobbie" />
      <link rel="apple-touch-icon" sizes="180x180" href="/apple-touch-icon.png" />
      <link rel="apple-touch-startup-image" media="(device-width: 1024px) and (device-height: 1366px) and (-webkit-device-pixel-ratio: 2)" href="/apple-splash-2048-2732.png" />
      <link rel="apple-touch-startup-image" media="(device-width: 834px) and (device-height: 1112px) and (-webkit-device-pixel-ratio: 2)" href="/apple-splash-1668-2224.png" />
      <link rel="apple-touch-startup-image" media="(device-width: 768px) and (device-height: 1024px) and (-webkit-device-pixel-ratio: 2)" href="/apple-splash-1536-2048.png" />
      <link rel="apple-touch-startup-image" media="(device-width: 375px) and (device-height: 812px) and (-webkit-device-pixel-ratio: 3)" href="/apple-splash-1125-2436.png" />
      <link rel="apple-touch-startup-image" media="(device-width: 414px) and (device-height: 896px) and (-webkit-device-pixel-ratio: 3)" href="/apple-splash-1242-2688.png" />
      <link rel="apple-touch-startup-image" media="(device-width: 428px) and (device-height: 926px) and (-webkit-device-pixel-ratio: 3)" href="/apple-splash-1284-2778.png" />
      <link rel="apple-touch-startup-image" media="(device-width: 375px) and (device-height: 667px) and (-webkit-device-pixel-ratio: 2)" href="/apple-splash-750-1334.png" />

      {/* Open Graph */}
      <meta property="og:title" content={title} />
      <meta property="og:description" content={description} />
      <meta property="og:image" content={ogImage} />
      <meta property="og:image:width" content="1200" />
      <meta property="og:image:height" content="630" />
      <meta property="og:image:alt" content="Bobbie Intelligence — Autonomous Intelligence Terminal" />
      <meta property="og:url" content={fullUrl} />
      <meta property="og:type" content={article ? "article" : "website"} />
      <meta property="og:site_name" content="Bobbie Intelligence" />
      <meta property="og:locale" content={locale} />
      {langPrefix === "vi" && <meta property="og:locale:alternate" content="en_US" />}
      {langPrefix === "en" && <meta property="og:locale:alternate" content="vi_VN" />}

      {/* Twitter */}
      <meta name="twitter:card" content="summary_large_image" />
      <meta name="twitter:title" content={title} />
      <meta name="twitter:description" content={description} />
      <meta name="twitter:image" content={ogImage} />
      <meta name="twitter:image:alt" content="Bobbie Intelligence — Autonomous Intelligence Terminal" />

      {/* JSON-LD */}
      <script type="application/ld+json">{JSON.stringify(jsonLd)}</script>
      <script type="application/ld+json">{JSON.stringify(breadcrumbLd)}</script>
    </>
  );
};

export default SEO;
