import React, { useContext } from "react";
import { Link, useStaticQuery, graphql } from "gatsby";
import { LangContext } from "./Layout";

const MarketTicker = ({ reports: injectedReports }) => {
  const { lang } = useContext(LangContext);
  const data = useStaticQuery(graphql`
    query TickerQuery {
      allMarkdownRemark(
        sort: { fields: { date: DESC } }
        limit: 30
      ) {
        nodes {
          id
          fields {
            slug
            date
            inferredTitle
            categoryIcon
            lang
            baseName
          }
        }
      }
    }
  `);

  const rawReports = injectedReports || data.allMarkdownRemark.nodes;

  // Deduplicate by baseName, pick current lang
  const seen = new Set();
  const reports = [];
  for (const r of rawReports) {
    const base = r.fields?.baseName || r.fields?.slug;
    if (seen.has(base)) continue;
    const matchLang = r.fields?.lang === lang;
    // First pass: pick matching lang
    if (matchLang && !seen.has(base)) {
      seen.add(base);
      reports.push(r);
    }
  }
  // Fill missing with en fallback
  for (const r of rawReports) {
    const base = r.fields?.baseName || r.fields?.slug;
    if (seen.has(base)) continue;
    if (r.fields?.lang === "en") {
      seen.add(base);
      reports.push(r);
    }
  }

  return (
    <div className="market-ticker" aria-label="Latest reports ticker">
      <div className="ticker-content">
        {reports.slice(0, 10).map((report, i) => {
          const title = report.fields?.inferredTitle || "Report";
          const icon = report.fields?.categoryIcon || "📄";
          const slug = `/${lang}${report.fields?.slug || "/"}`;
          return (
            <React.Fragment key={report.id}>
              {i > 0 && <span className="ticker-sep">|</span>}
              <Link to={slug} className="ticker-link">
                {icon} {title.length > 60 ? title.substring(0, 60) + "…" : title}
              </Link>
            </React.Fragment>
          );
        })}
      </div>
    </div>
  );
};

export default MarketTicker;
